// --- BRAND LOGO COMPONENT ---------------------------------
const CuePointLogo = ({ size = 48, showText = false, textSize = 22 }) => {
  const id = "cpg" + size;
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: showText ? 8 : 0 }}>
      <svg width={size} height={size * 1.1} viewBox="0 0 100 110" fill="none" xmlns="http://www.w3.org/2000/svg">
        <defs>
          <linearGradient id={id} x1="50" y1="0" x2="50" y2="100" gradientUnits="userSpaceOnUse">
            <stop offset="0%" stopColor="#F472B6" />
            <stop offset="50%" stopColor="#A855F7" />
            <stop offset="100%" stopColor="#22D3EE" />
          </linearGradient>
        </defs>
        {/* Map pin shape */}
        <path d="M50 2C34.5 2 22 14.5 22 30C22 47 50 72 50 72C50 72 78 47 78 30C78 14.5 65.5 2 50 2Z"
          fill={"url(#" + id + ")"} opacity="0.92" />
        {/* Inner circle cutout */}
        <circle cx="50" cy="30" r="13" fill="white" opacity="0.9" />
        {/* Sound wave bars */}
        {[
          [50, 85, 18], [42, 88, 12], [34, 90, 8], [26, 92, 5], [18, 93, 3],
          [58, 88, 12], [66, 90, 8], [74, 92, 5], [82, 93, 3],
        ].map(([x, y, h], i) => (
          <rect key={i} x={x - 1.5} y={y - h / 2} width={3} height={h} rx={1.5}
            fill="#A1A1AA" opacity={0.7 - i * 0.04} />
        ))}
      </svg>
      {showText && (
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: textSize, fontWeight: 900, letterSpacing: "-0.03em", color: "#2D2D3A", lineHeight: 1 }}>
            CUE POINT
          </div>
          <div style={{ fontSize: textSize * 0.52, fontWeight: 700, letterSpacing: "0.22em", color: BRAND_ACCENT, textTransform: "uppercase", marginTop: 2 }}>
            PLANNING
          </div>
        </div>
      )}
    </div>
  );
};

// --- PERSISTENT STORAGE HOOK ------------------------------
// Reads from localStorage immediately (fast), then syncs with Supabase in background.
// Writes go to both localStorage (instant UI) and Supabase (cloud backup).
const useLocalStorage = (key, initial) => {
  const [val, setValRaw] = useState(() => {
    try {
      const stored = localStorage.getItem("cuepoint_" + key);
      return stored ? JSON.parse(stored) : initial;
    } catch { return initial; }
  });

  // Sync FROM Supabase on mount (hydrate with cloud data if available)
  useEffect(() => {
    const load = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return;
        const { data, error } = await supabase
          .from("user_data")
          .select("value")
          .eq("user_id", session.user.id)
          .eq("key", key)
          .single();
        if (!error && data?.value !== undefined && data.value !== null) {
          setValRaw(data.value);
          try { localStorage.setItem("cuepoint_" + key, JSON.stringify(data.value)); } catch {}
        }
      } catch {}
    };
    load();
  }, [key]);

  const setVal = React.useCallback((updater) => {
    setValRaw(prev => {
      const next = typeof updater === "function" ? updater(prev) : updater;
      // Write to localStorage immediately
      try { localStorage.setItem("cuepoint_" + key, JSON.stringify(next)); } catch {}
      // Write to Supabase in background
      supabase.auth.getSession().then(({ data: { session } }) => {
        if (!session?.user) return;
        supabase.from("user_data").upsert({
          user_id: session.user.id,
          key,
          value: next,
          updated_at: new Date().toISOString(),
        }, { onConflict: "user_id,key" }).then(() => {});
      });
      return next;
    });
  }, [key]);

  return [val, setVal];
};

// --- SYNCHRONOUS STORAGE MIGRATION (runs once at module load) ----
try {
  const KEY = "cuepoint_pricingPackages";
  const raw = localStorage.getItem(KEY);
  if (raw) {
    const arr = JSON.parse(raw);
    if (Array.isArray(arr)) {
      const needsMigration = arr.some(p => "photo" in p || "photoColor" in p || "badge" in p || typeof p.price !== "number");
      if (needsMigration) {
        localStorage.removeItem(KEY);
      }
    }
  }
} catch(e) {}

