// --- UTILITY COMPONENTS -----------------------------------
const Badge = ({ children, color = C.accent, size = "sm" }) => (
  <span style={{
    background: color + "20", color, border: `1px solid ${color}35`,
    borderRadius: 5, padding: size === "sm" ? "2px 8px" : "4px 12px",
    fontSize: size === "sm" ? 11 : 13, fontWeight: 700,
    letterSpacing: "0.03em", textTransform: "uppercase", whiteSpace: "nowrap",
  }}>{children}</span>
);

const Btn = ({ children, onClick, variant = "primary", size = "md", style = {}, disabled }) => {
  const [hov, setHov] = useState(false);
  const base = {
    fontFamily: "'DM Sans', sans-serif", cursor: disabled ? "not-allowed" : "pointer",
    border: "none", borderRadius: 8, fontWeight: 600,
    transition: "all 0.15s", opacity: disabled ? 0.45 : 1,
    fontSize: size === "sm" ? 12 : size === "lg" ? 15 : 13,
    padding: size === "sm" ? "6px 13px" : size === "lg" ? "13px 30px" : "8px 18px",
    letterSpacing: "0.01em", display: "inline-flex", alignItems: "center", gap: 6,
  };
  const variants = {
    primary: { background: hov ? C.accent + "EE" : C.accent, color: "#fff", boxShadow: hov ? `0 4px 16px ${C.accent}44` : "none" },
    secondary: { background: hov ? "#f0f0f0" : "#fff", color: "#000", border: "2px solid #000", fontWeight: 700 },
    ghost: { background: hov ? "#f0f0f0" : "#fff", color: "#000", border: "2px solid #000", fontWeight: 700 },
    danger: { background: hov ? C.red + "15" : "#fff", color: C.red, border: `2px solid ${C.red}`, fontWeight: 700 },
    success: { background: hov ? C.green + "15" : "#fff", color: C.green, border: `2px solid ${C.green}`, fontWeight: 700 },
  };
  return <button onClick={onClick} disabled={disabled}
    onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
    style={{ ...base, ...variants[variant], ...style }}>{children}</button>;
};

const Card = ({ children, style = {}, glow, hover, onClick }) => {
  const [hov, setHov] = useState(false);
  return (
    <div onClick={onClick}
      onMouseEnter={() => hover && setHov(true)}
      onMouseLeave={() => hover && setHov(false)}
      style={{
        background: hov && hover ? C.surfaceHover : C.surface,
        border: `1px solid ${hov && hover ? C.borderLight : C.border}`,
        borderRadius: 12, padding: 20,
        boxShadow: hov && hover ? "0 2px 16px rgba(0,0,0,0.08)" : "none",
        cursor: onClick ? "pointer" : "default",
        transition: "all 0.15s",
        ...style,
      }}>{children}</div>
  );
};

const Input = ({ label, value, onChange, placeholder, type = "text", style = {} }) => (
  <div style={{ marginBottom: 16, ...style }}>
    {label && <div style={{ fontSize: 11, color: C.muted, fontWeight: 600, marginBottom: 5, textTransform: "uppercase", letterSpacing: "0.06em" }}>{label}</div>}
    <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
      style={{
        width: "100%", background: C.surfaceAlt, border: `1px solid ${C.border}`,
        borderRadius: 8, padding: "9px 13px", color: C.text, fontSize: 13.5,
        fontFamily: "'DM Sans', sans-serif", outline: "none", boxSizing: "border-box",
        transition: "border-color 0.15s",
      }}
      onFocus={e => e.target.style.borderColor = C.accent + "88"}
      onBlur={e => e.target.style.borderColor = C.border}
    /> </div>
);

const Select = ({ label, value, onChange, options }) => (
  <div style={{ marginBottom: 16 }}>
    {label && <div style={{ fontSize: 12, color: C.muted, fontWeight: 600, marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.05em" }}>{label}</div>}
    <select value={value} onChange={e => onChange(e.target.value)}
      style={{
        width: "100%", background: C.surfaceAlt, border: `1px solid ${C.border}`,
        borderRadius: 8, padding: "10px 14px", color: C.text, fontSize: 14,
        fontFamily: "'DM Sans', sans-serif", outline: "none",
      }}>
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select> </div>
);

const Stat = ({ label, value, sub, color = C.accent, icon, trend }) => (
  <div style={{ flex: 1, minWidth: 150, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: "16px 18px", borderLeft: `3px solid ${color}` }}> <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}> <div style={{ flex: 1 }}> <div style={{ color: C.muted, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 8 }}>{label}</div> <div style={{ fontSize: 24, fontWeight: 700, color: C.text, letterSpacing: "-0.02em", marginBottom: 3 }}>{value}</div>
        {sub && <div style={{ fontSize: 12, color: trend === "up" ? C.green : trend === "down" ? C.red : C.muted }}>{trend === "up" ? "↑ " : trend === "down" ? "↓ " : ""}{sub}</div>}
      </div> <div style={{ width: 38, height: 38, borderRadius: 10, background: color + "18", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 17 }}>{icon || ""}</div> </div> </div>
);

const Tab = ({ tabs, active, setActive }) => (
  <div style={{ display: "flex", gap: 4, background: C.surfaceAlt, borderRadius: 10, padding: 4, marginBottom: 24 }}>
    {tabs.map(t => (
      <button key={t} onClick={() => setActive(t)} style={{
        flex: 1, padding: "8px 12px", borderRadius: 7, border: "none", cursor: "pointer",
        background: active === t ? C.surface : "transparent",
        color: active === t ? C.text : C.muted,
        fontWeight: active === t ? 700 : 500, fontSize: 13,
        fontFamily: "'DM Sans', sans-serif",
        boxShadow: active === t ? `0 1px 4px rgba(0,0,0,0.4)` : "none",
        transition: "all 0.15s",
      }}>{t}</button>
    ))}
  </div>
);

const ProgressBar = ({ value, color = C.accent, height = 6 }) => (
  <div style={{ height, background: C.border, borderRadius: height }}> <div style={{ height: "100%", width: `${Math.min(100, value)}%`, borderRadius: height, background: `linear-gradient(90deg, ${color}, ${color}BB)`, transition: "width 0.6s ease" }} /> </div>
);

