const Templates = ({ setSection }) => {
  const { contractTemplates, customQuestionnaires, customTexts } = useApp();
  const [activeTab, setActiveTab] = useState("contracts");
  const [copiedId, setCopiedId] = useState(null);
  const [expandedTimeline, setExpandedTimeline] = useState(null);
  const [expandedScript, setExpandedScript] = useState(null);
  const [expandedEmail, setExpandedEmail] = useState(null);

  const contractTpls = contractTemplates || DEFAULT_TEMPLATES;
  const questionnaireTpls = customQuestionnaires.length > 0 ? customQuestionnaires : DEFAULT_Q_TEMPLATES;
  const emailTpls = TEMPLATE_QUICK_TEXTS;
  const emailCategories = [...new Set(emailTpls.map(t => t.category))];

  const copyToClipboard = (text, id) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const TABS = [
    { id: "contracts",      label: "Contracts",     icon: "📄", count: contractTpls.length },
    { id: "emails",         label: "Emails",        icon: "📧", count: emailTpls.length },
    { id: "timelines",      label: "Timelines",     icon: "⏱",  count: TIMELINE_TEMPLATES.length },
    { id: "mcscripts",      label: "MC Scripts",    icon: "🎤", count: MC_SCRIPT_TEMPLATES.length },
    { id: "questionnaires", label: "Questionnaires",icon: "📋", count: questionnaireTpls.length },
  ];

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 900, marginBottom: 4 }}>Templates</h2>
          <p style={{ color: C.muted, fontSize: 13 }}>Reusable templates across contracts, emails, timelines, MC scripts, and questionnaires.</p>
        </div>
      </div>

      {/* Tab bar */}
      <div style={{ display: "flex", gap: 6, marginBottom: 24, flexWrap: "wrap" }}>
        {TABS.map(t => (
          <div key={t.id} onClick={() => setActiveTab(t.id)}
            style={{ display: "flex", alignItems: "center", gap: 7, padding: "8px 16px",
              borderRadius: 9, cursor: "pointer", fontSize: 13, fontWeight: 600,
              background: activeTab === t.id ? C.accent : C.surface,
              color: activeTab === t.id ? "#fff" : C.muted,
              border: `1px solid ${activeTab === t.id ? C.accent : C.border}`,
              transition: "all 0.15s" }}>
            <span>{t.icon}</span>
            <span>{t.label}</span>
            <span style={{ background: activeTab === t.id ? "rgba(255,255,255,0.2)" : C.surfaceAlt,
              borderRadius: 10, padding: "1px 7px", fontSize: 11 }}>{t.count}</span>
          </div>
        ))}
      </div>

      {/* ── CONTRACTS ── */}
      {activeTab === "contracts" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <div style={{ fontSize: 13, color: C.muted }}>{contractTpls.length} templates — edit and create more in the Contracts section</div>
            <Btn size="sm" variant="ghost" onClick={() => setSection && setSection("contracts")}>Go to Contracts →</Btn>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 14 }}>
            {contractTpls.map(tpl => (
              <Card key={tpl.id} style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 10 }}>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>{tpl.name}</div>
                    <div style={{ fontSize: 11, color: C.muted }}>{tpl.type || "General"}</div>
                  </div>
                  <div style={{ fontSize: 22, flexShrink: 0 }}>📄</div>
                </div>
                <div style={{ fontSize: 12, color: C.muted, lineHeight: 1.5,
                  background: C.surfaceAlt, borderRadius: 7, padding: "8px 10px",
                  maxHeight: 60, overflow: "hidden", fontFamily: "monospace" }}>
                  {(tpl.body || "").slice(0, 120)}…
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <Btn size="sm" onClick={() => setSection && setSection("contracts")}>Use Template</Btn>
                  <Btn size="sm" variant="ghost" onClick={() => copyToClipboard(tpl.body || "", tpl.id)}>
                    {copiedId === tpl.id ? "✓ Copied" : "Copy Text"}
                  </Btn>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* ── EMAILS ── */}
      {activeTab === "emails" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <div style={{ fontSize: 13, color: C.muted }}>Built-in email and text templates. Add custom ones in Quick Texts.</div>
            <Btn size="sm" variant="ghost" onClick={() => setSection && setSection("quicktexts")}>Go to Quick Texts →</Btn>
          </div>
          {emailCategories.map(cat => (
            <div key={cat} style={{ marginBottom: 20 }}>
              <div style={{ fontWeight: 700, fontSize: 13, color: C.accent, marginBottom: 10,
                textTransform: "uppercase", letterSpacing: "0.07em", fontSize: 11 }}>{cat}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {emailTpls.filter(t => t.category === cat).map(tpl => (
                  <div key={tpl.id}
                    style={{ background: C.surface, border: `1px solid ${expandedEmail === tpl.id ? C.accent + "60" : C.border}`,
                      borderRadius: 10, overflow: "hidden", transition: "border-color 0.15s" }}>
                    <div onClick={() => setExpandedEmail(expandedEmail === tpl.id ? null : tpl.id)}
                      style={{ display: "flex", justifyContent: "space-between", alignItems: "center",
                        padding: "12px 16px", cursor: "pointer" }}>
                      <div style={{ fontWeight: 600, fontSize: 13 }}>{tpl.label}</div>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <Btn size="sm" variant="ghost" onClick={e => { e.stopPropagation(); copyToClipboard(tpl.body, tpl.id); }}>
                          {copiedId === tpl.id ? "✓ Copied" : "Copy"}
                        </Btn>
                        <span style={{ color: C.muted, fontSize: 12 }}>{expandedEmail === tpl.id ? "▲" : "▼"}</span>
                      </div>
                    </div>
                    {expandedEmail === tpl.id && (
                      <div style={{ padding: "0 16px 14px", fontSize: 12, color: C.muted,
                        lineHeight: 1.65, borderTop: `1px solid ${C.border}`, paddingTop: 12 }}>
                        {tpl.body}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── TIMELINES ── */}
      {activeTab === "timelines" && (
        <div>
          <div style={{ fontSize: 13, color: C.muted, marginBottom: 16 }}>
            Pre-built run-of-show timelines. Click to preview, then use in DJ Planning.
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))", gap: 14 }}>
            {TIMELINE_TEMPLATES.map(tpl => (
              <Card key={tpl.id}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>{tpl.name}</div>
                    <div style={{ fontSize: 11, color: C.muted }}>{tpl.items.length} time slots</div>
                  </div>
                  <div style={{ fontSize: 20 }}>⏱</div>
                </div>
                {/* Preview: first 3 items */}
                <div style={{ display: "flex", flexDirection: "column", gap: 4, marginBottom: 14 }}>
                  {(expandedTimeline === tpl.id ? tpl.items : tpl.items.slice(0, 4)).map((item, i) => (
                    <div key={i} style={{ display: "flex", gap: 10, fontSize: 12, alignItems: "flex-start" }}>
                      <span style={{ color: C.accent, fontWeight: 700, flexShrink: 0, width: 60, fontFamily: "monospace", fontSize: 11 }}>{item.time}</span>
                      <span style={{ color: C.muted }}>{item.label}</span>
                    </div>
                  ))}
                  {expandedTimeline !== tpl.id && tpl.items.length > 4 && (
                    <div style={{ fontSize: 11, color: C.muted2, paddingLeft: 70 }}>+ {tpl.items.length - 4} more…</div>
                  )}
                </div>
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  <Btn size="sm" variant="ghost" onClick={() => setExpandedTimeline(expandedTimeline === tpl.id ? null : tpl.id)}>
                    {expandedTimeline === tpl.id ? "Collapse" : "Show All"}
                  </Btn>
                  <Btn size="sm" variant="ghost" onClick={() => {
                    const text = tpl.items.map(i => `${i.time} — ${i.label}`).join("\n");
                    copyToClipboard(text, tpl.id);
                  }}>
                    {copiedId === tpl.id ? "✓ Copied" : "Copy Timeline"}
                  </Btn>
                  <Btn size="sm" onClick={() => setSection && setSection("djplanning")}>Open DJ Planning</Btn>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* ── MC SCRIPTS ── */}
      {activeTab === "mcscripts" && (
        <div>
          <div style={{ fontSize: 13, color: C.muted, marginBottom: 16 }}>
            Ready-to-use MC announcement scripts. Customize the [BRACKETS] for each event.
          </div>
          {[...new Set(MC_SCRIPT_TEMPLATES.map(s => s.category))].map(cat => (
            <div key={cat} style={{ marginBottom: 24 }}>
              <div style={{ fontWeight: 700, fontSize: 11, color: C.accent, marginBottom: 10,
                textTransform: "uppercase", letterSpacing: "0.07em" }}>{cat}</div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {MC_SCRIPT_TEMPLATES.filter(s => s.category === cat).map(script => (
                  <div key={script.id}
                    style={{ background: C.surface, border: `1px solid ${expandedScript === script.id ? C.accent + "60" : C.border}`,
                      borderRadius: 10, overflow: "hidden", transition: "border-color 0.15s" }}>
                    <div onClick={() => setExpandedScript(expandedScript === script.id ? null : script.id)}
                      style={{ display: "flex", justifyContent: "space-between", alignItems: "center",
                        padding: "12px 16px", cursor: "pointer" }}>
                      <div style={{ fontWeight: 600, fontSize: 13 }}>{script.label}</div>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <Btn size="sm" variant="ghost" onClick={e => { e.stopPropagation(); copyToClipboard(script.script, script.id); }}>
                          {copiedId === script.id ? "✓ Copied" : "Copy"}
                        </Btn>
                        <span style={{ color: C.muted, fontSize: 12 }}>{expandedScript === script.id ? "▲" : "▼"}</span>
                      </div>
                    </div>
                    {expandedScript === script.id && (
                      <div style={{ padding: "12px 16px 14px", borderTop: `1px solid ${C.border}` }}>
                        <div style={{ fontSize: 13, color: C.text, lineHeight: 1.75, whiteSpace: "pre-wrap",
                          background: C.surfaceAlt, borderRadius: 7, padding: "12px 14px" }}>
                          {script.script}
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ── QUESTIONNAIRES ── */}
      {activeTab === "questionnaires" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <div style={{ fontSize: 13, color: C.muted }}>{questionnaireTpls.length} templates — edit and assign in the Questionnaires section.</div>
            <Btn size="sm" variant="ghost" onClick={() => setSection && setSection("questionnaires")}>Go to Questionnaires →</Btn>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 14 }}>
            {questionnaireTpls.map(tpl => (
              <Card key={tpl.id} style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 3 }}>{tpl.name}</div>
                    <div style={{ fontSize: 11, color: C.muted }}>
                      {tpl.sections?.length || 0} sections · {tpl.questions?.length || 0} questions
                    </div>
                  </div>
                  <div style={{ fontSize: 22 }}>📋</div>
                </div>
                {tpl.sections && (
                  <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                    {tpl.sections.map((s, i) => (
                      <div key={i} style={{ fontSize: 12, color: C.muted, display: "flex", gap: 8, alignItems: "center" }}>
                        <span style={{ width: 6, height: 6, borderRadius: "50%", background: C.accent, flexShrink: 0, display: "inline-block" }} />
                        {s.label}
                      </div>
                    ))}
                  </div>
                )}
                <Btn size="sm" onClick={() => setSection && setSection("questionnaires")}>Use Template</Btn>
              </Card>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};


// --- REPORTS --------------------------------------------------
const Reports = ({ setSection }) => {
  const { events, invoices, expenses, leads, clients, debriefs, mileage, payroll } = useApp();
  const [year, setYear] = useState(new Date().getFullYear());
  const [activeTab, setActiveTab] = useState("overview");

  const { BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
          XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } = window.Recharts || {};

  const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

  // ── helpers ───────────────────────────────────────────
  const inYear = (dateStr) => dateStr && new Date(dateStr).getFullYear() === year;
  const fmt = (n) => "$" + Number(n || 0).toLocaleString();
  const pct = (a, b) => b === 0 ? null : ((a - b) / b * 100).toFixed(1);

  // ── revenue ───────────────────────────────────────────
  const paidInvoices  = (invoices || []).filter(i => i.status === "Paid" && inYear(i.paidDate));
  const totalRevenue  = paidInvoices.reduce((s, i) => s + (Number(i.amount) || 0), 0);
  const totalExpenses = (expenses || []).filter(e => inYear(e.date)).reduce((s, e) => s + (Number(e.amount) || 0), 0);
  const totalMileage  = (mileage  || []).filter(m => inYear(m.date)).reduce((s, m) => s + (Number(m.miles) || 0), 0);
  const mileageValue  = totalMileage * 0.67; // IRS rate
  const totalPayroll  = (payroll  || []).filter(p => inYear(p.date)).reduce((s, p) => s + (Number(p.amount) || 0), 0);
  const netProfit     = totalRevenue - totalExpenses - totalPayroll;

  // prev year comparisons
  const prevPaid    = (invoices || []).filter(i => i.status === "Paid" && i.paidDate && new Date(i.paidDate).getFullYear() === year - 1);
  const prevRevenue = prevPaid.reduce((s, i) => s + (Number(i.amount) || 0), 0);
  const revenueChange = pct(totalRevenue, prevRevenue);

  // ── monthly revenue chart ─────────────────────────────
  const monthlyRevenue = MONTHS.map((m, mi) => {
    const rev = paidInvoices.filter(i => new Date(i.paidDate).getMonth() === mi)
                            .reduce((s, i) => s + (Number(i.amount) || 0), 0);
    const exp = (expenses || []).filter(e => inYear(e.date) && new Date(e.date).getMonth() === mi)
                                .reduce((s, e) => s + (Number(e.amount) || 0), 0);
    return { month: m, Revenue: rev, Expenses: exp, Profit: rev - exp };
  });

  // ── events by type ────────────────────────────────────
  const yearEvents = (events || []).filter(e => inYear(e.date));
  const eventsByType = (() => {
    const map = {};
    yearEvents.forEach(e => { const t = e.type || "Other"; map[t] = (map[t] || 0) + 1; });
    return Object.entries(map).map(([name, value]) => ({ name, value }));
  })();

  const eventsByMonth = MONTHS.map((m, mi) => ({
    month: m,
    Events: yearEvents.filter(e => new Date(e.date).getMonth() === mi).length,
  }));

  // ── leads funnel ──────────────────────────────────────
  const yearLeads   = (leads || []).filter(l => inYear(l.createdAt));
  const leadStages  = ["New","Contacted","Proposal Sent","Negotiating","Booked","Lost"];
  const leadFunnel  = leadStages.map(s => ({
    stage: s, count: yearLeads.filter(l => l.stage === s).length
  })).filter(s => s.count > 0);
  const convRate    = yearLeads.length > 0
    ? ((yearLeads.filter(l => l.stage === "Booked").length / yearLeads.length) * 100).toFixed(0) : 0;

  // ── expenses by category ──────────────────────────────
  const expByCategory = (() => {
    const map = {};
    (expenses || []).filter(e => inYear(e.date)).forEach(e => {
      const cat = e.category || "Other";
      map[cat] = (map[cat] || 0) + (Number(e.amount) || 0);
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value);
  })();

  // ── client metrics ────────────────────────────────────
  const avgEventValue = yearEvents.filter(e => e.totalFee > 0).length > 0
    ? (yearEvents.reduce((s, e) => s + (Number(e.totalFee) || 0), 0) / yearEvents.filter(e => e.totalFee > 0).length)
    : 0;

  const repeatClients = (() => {
    const map = {};
    (events || []).forEach(e => { if (e.client) map[e.client] = (map[e.client] || 0) + 1; });
    return Object.values(map).filter(c => c > 1).length;
  })();

  // ── debriefs ─────────────────────────────────────────
  const debriefsArr = Object.values(debriefs || {});
  const yearDebriefs = debriefsArr.filter(d => d.rating);
  const avgRating   = yearDebriefs.length > 0
    ? (yearDebriefs.reduce((s, d) => s + (Number(d.rating) || 0), 0) / yearDebriefs.length).toFixed(1) : null;

  // ── PIE COLORS ────────────────────────────────────────
  const PIE_COLORS = [C.accent, C.purple, C.green, C.orange, C.pink, C.yellow, C.red, C.teal];

  const TABS = [
    { id: "overview",   label: "Overview" },
    { id: "revenue",    label: "Revenue" },
    { id: "events",     label: "Events" },
    { id: "leads",      label: "Leads" },
    { id: "expenses",   label: "Expenses" },
  ];

  const ChartCard = ({ title, sub, children, style }) => (
    <Card style={{ marginBottom: 0, ...style }}>
      <div style={{ fontWeight: 700, fontSize: 14, marginBottom: sub ? 2 : 16 }}>{title}</div>
      {sub && <div style={{ fontSize: 12, color: C.muted, marginBottom: 16 }}>{sub}</div>}
      {children}
    </Card>
  );

  const KpiCard = ({ label, value, sub, color, change }) => (
    <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: "18px 20px" }}>
      <div style={{ fontSize: 11, color: C.muted, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.07em", marginBottom: 8 }}>{label}</div>
      <div style={{ fontSize: 28, fontWeight: 900, color: color || C.text, letterSpacing: "-0.02em", marginBottom: 4 }}>{value}</div>
      <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
        {sub && <span style={{ fontSize: 12, color: C.muted }}>{sub}</span>}
        {change !== null && change !== undefined && (
          <span style={{ fontSize: 11, fontWeight: 700, color: Number(change) >= 0 ? C.green : C.red }}>
            {Number(change) >= 0 ? "↑" : "↓"} {Math.abs(change)}% vs {year - 1}
          </span>
        )}
      </div>
    </div>
  );

  const noData = (msg) => (
    <div style={{ textAlign: "center", padding: "40px 20px", color: C.muted, fontSize: 13 }}>
      <div style={{ fontSize: 32, marginBottom: 10, opacity: 0.3 }}>📊</div>
      {msg}
    </div>
  );

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 900, marginBottom: 4 }}>Reports</h2>
          <p style={{ color: C.muted, fontSize: 13 }}>Business performance, revenue trends, and key metrics across all your data.</p>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <select value={year} onChange={e => setYear(Number(e.target.value))}
            style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8,
              padding: "8px 14px", color: C.text, fontSize: 13, fontFamily: "inherit", outline: "none" }}>
            {[2023,2024,2025,2026,2027].map(y => <option key={y} value={y}>{y}</option>)}
          </select>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 6, marginBottom: 24, flexWrap: "wrap" }}>
        {TABS.map(t => (
          <div key={t.id} onClick={() => setActiveTab(t.id)}
            style={{ padding: "8px 18px", borderRadius: 9, cursor: "pointer",
              fontSize: 13, fontWeight: 600, transition: "all 0.15s",
              background: activeTab === t.id ? C.accent : C.surface,
              color: activeTab === t.id ? "#fff" : C.muted,
              border: `1px solid ${activeTab === t.id ? C.accent : C.border}` }}>
            {t.label}
          </div>
        ))}
      </div>

      {/* ── OVERVIEW TAB ── */}
      {activeTab === "overview" && (
        <div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 20 }}>
            <KpiCard label="Total Revenue" value={fmt(totalRevenue)} sub={`${paidInvoices.length} paid invoices`} color={C.green} change={revenueChange} />
            <KpiCard label="Net Profit" value={fmt(netProfit)} sub="Revenue minus expenses & payroll" color={netProfit >= 0 ? C.accent : C.red} />
            <KpiCard label="Total Events" value={yearEvents.length} sub={`Avg ${fmt(avgEventValue)} / event`} color={C.purple} />
            <KpiCard label="Avg Rating" value={avgRating ? `${avgRating} ★` : "—"} sub={`${yearDebriefs.length} debriefs logged`} color={C.yellow} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 24 }}>
            <KpiCard label="Total Expenses" value={fmt(totalExpenses)} sub="Logged expenses" color={C.orange} />
            <KpiCard label="Mileage" value={`${totalMileage.toLocaleString()} mi`} sub={`${fmt(mileageValue)} deductible`} color={C.teal} />
            <KpiCard label="Lead Conversion" value={`${convRate}%`} sub={`${yearLeads.length} leads total`} color={C.pink} />
            <KpiCard label="Repeat Clients" value={repeatClients} sub="Clients with 2+ events" color={C.accent} />
          </div>
          {BarChart ? (
            <ChartCard title="Revenue vs Expenses" sub={`Monthly breakdown for ${year}`}>
              <ResponsiveContainer width="100%" height={240}>
                <BarChart data={monthlyRevenue} margin={{ top: 4, right: 0, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                  <XAxis dataKey="month" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => "$" + (v >= 1000 ? (v/1000).toFixed(0)+"k" : v)} />
                  <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} formatter={v => fmt(v)} />
                  <Legend wrapperStyle={{ fontSize: 12 }} />
                  <Bar dataKey="Revenue" fill={C.accent} radius={[4,4,0,0]} />
                  <Bar dataKey="Expenses" fill={C.red + "aa"} radius={[4,4,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </ChartCard>
          ) : noData("Charts loading...")}
        </div>
      )}

      {/* ── REVENUE TAB ── */}
      {activeTab === "revenue" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12 }}>
            <KpiCard label="Total Revenue" value={fmt(totalRevenue)} change={revenueChange} color={C.green} />
            <KpiCard label="Payroll Paid" value={fmt(totalPayroll)} sub={`${(payroll||[]).filter(p=>inYear(p.date)).length} entries`} color={C.orange} />
            <KpiCard label="Net Profit" value={fmt(netProfit)} color={netProfit >= 0 ? C.accent : C.red} />
          </div>
          {BarChart ? (<>
            <ChartCard title="Monthly Revenue" sub="Paid invoices by month">
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={monthlyRevenue}>
                  <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                  <XAxis dataKey="month" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => "$"+(v>=1000?(v/1000).toFixed(0)+"k":v)} />
                  <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} formatter={v => fmt(v)} />
                  <Bar dataKey="Revenue" fill={C.accent} radius={[4,4,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </ChartCard>
            <ChartCard title="Monthly Profit" sub="Revenue minus expenses">
              <ResponsiveContainer width="100%" height={200}>
                <LineChart data={monthlyRevenue}>
                  <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                  <XAxis dataKey="month" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => "$"+(v>=1000?(v/1000).toFixed(0)+"k":v)} />
                  <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} formatter={v => fmt(v)} />
                  <Line type="monotone" dataKey="Profit" stroke={C.green} strokeWidth={2} dot={{ fill: C.green, r: 3 }} />
                </LineChart>
              </ResponsiveContainer>
            </ChartCard>
          </>) : noData("Add paid invoices to see revenue charts")}
        </div>
      )}

      {/* ── EVENTS TAB ── */}
      {activeTab === "events" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
            <KpiCard label="Total Events" value={yearEvents.length} color={C.accent} />
            <KpiCard label="Avg Event Value" value={fmt(avgEventValue)} color={C.green} />
            <KpiCard label="Unique Clients" value={new Set(yearEvents.map(e => e.client).filter(Boolean)).size} color={C.purple} />
            <KpiCard label="Repeat Clients" value={repeatClients} color={C.orange} />
          </div>
          {yearEvents.length === 0 ? noData("No events found for this year") : BarChart ? (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <ChartCard title="Events by Month">
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={eventsByMonth}>
                    <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                    <XAxis dataKey="month" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} />
                    <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} />
                    <Bar dataKey="Events" fill={C.purple} radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </ChartCard>
              <ChartCard title="Events by Type">
                {eventsByType.length === 0 ? noData("No event types found") : (
                  <ResponsiveContainer width="100%" height={220}>
                    <PieChart>
                      <Pie data={eventsByType} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={({ name, percent }) => `${name} ${(percent*100).toFixed(0)}%`} labelLine={false}>
                        {eventsByType.map((_, i) => <Cell key={i} fill={PIE_COLORS[i % PIE_COLORS.length]} />)}
                      </Pie>
                      <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} />
                    </PieChart>
                  </ResponsiveContainer>
                )}
              </ChartCard>
            </div>
          ) : noData("Charts loading...")}
        </div>
      )}

      {/* ── LEADS TAB ── */}
      {activeTab === "leads" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
            <KpiCard label="Total Leads" value={yearLeads.length} color={C.accent} />
            <KpiCard label="Booked" value={yearLeads.filter(l => l.stage === "Booked").length} color={C.green} />
            <KpiCard label="Lost" value={yearLeads.filter(l => l.stage === "Lost").length} color={C.red} />
            <KpiCard label="Conversion Rate" value={`${convRate}%`} color={C.purple} />
          </div>
          {yearLeads.length === 0 ? noData("No leads found for this year") : (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <ChartCard title="Pipeline Funnel">
                {leadFunnel.length === 0 ? noData("No lead stage data") : BarChart ? (
                  <ResponsiveContainer width="100%" height={220}>
                    <BarChart data={leadFunnel} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                      <XAxis type="number" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} />
                      <YAxis type="category" dataKey="stage" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} width={100} />
                      <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} />
                      <Bar dataKey="count" fill={C.accent} radius={[0,4,4,0]} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : noData("Charts loading...")}
              </ChartCard>
              <ChartCard title="Lead Sources">
                {(() => {
                  const srcMap = {};
                  yearLeads.forEach(l => { const s = l.source || "Direct"; srcMap[s] = (srcMap[s]||0)+1; });
                  const srcData = Object.entries(srcMap).map(([name, value]) => ({ name, value }));
                  return srcData.length === 0 ? noData("No source data") : PieChart ? (
                    <ResponsiveContainer width="100%" height={220}>
                      <PieChart>
                        <Pie data={srcData} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={({ name, percent }) => `${name} ${(percent*100).toFixed(0)}%`} labelLine={false}>
                          {srcData.map((_, i) => <Cell key={i} fill={PIE_COLORS[i % PIE_COLORS.length]} />)}
                        </Pie>
                        <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} />
                      </PieChart>
                    </ResponsiveContainer>
                  ) : noData("Charts loading...");
                })()}
              </ChartCard>
            </div>
          )}
        </div>
      )}

      {/* ── EXPENSES TAB ── */}
      {activeTab === "expenses" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
            <KpiCard label="Total Expenses" value={fmt(totalExpenses)} color={C.red} />
            <KpiCard label="Mileage Deduction" value={fmt(mileageValue)} sub={`${totalMileage.toLocaleString()} miles @ $0.67`} color={C.teal} />
            <KpiCard label="Payroll Paid" value={fmt(totalPayroll)} color={C.orange} />
            <KpiCard label="Total Deductions" value={fmt(totalExpenses + mileageValue + totalPayroll)} color={C.purple} />
          </div>
          {expByCategory.length === 0 ? noData("No expenses logged for this year. Add expenses in Financials.") : (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <ChartCard title="Expenses by Category">
                {BarChart ? (
                  <ResponsiveContainer width="100%" height={240}>
                    <BarChart data={expByCategory} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" stroke={C.border} />
                      <XAxis type="number" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} tickFormatter={v => "$"+(v>=1000?(v/1000).toFixed(0)+"k":v)} />
                      <YAxis type="category" dataKey="name" tick={{ fill: C.muted, fontSize: 11 }} axisLine={false} tickLine={false} width={100} />
                      <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} formatter={v => fmt(v)} />
                      <Bar dataKey="value" fill={C.orange} radius={[0,4,4,0]} />
                    </BarChart>
                  </ResponsiveContainer>
                ) : noData("Charts loading...")}
              </ChartCard>
              <ChartCard title="Expense Breakdown">
                {PieChart ? (
                  <ResponsiveContainer width="100%" height={240}>
                    <PieChart>
                      <Pie data={expByCategory} cx="50%" cy="50%" outerRadius={90} dataKey="value" label={({ name, percent }) => `${name} ${(percent*100).toFixed(0)}%`} labelLine={false}>
                        {expByCategory.map((_, i) => <Cell key={i} fill={PIE_COLORS[i % PIE_COLORS.length]} />)}
                      </Pie>
                      <Tooltip contentStyle={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 12 }} formatter={v => fmt(v)} />
                    </PieChart>
                  </ResponsiveContainer>
                ) : noData("Charts loading...")}
              </ChartCard>
            </div>
          )}
        </div>
      )}
    </div>
  );
};


// --- WARDROBE ---------------------------------------------
const SUIT_STATUSES = [
  { label: "Clean & Ready",        color: "#16A34A", bg: "#16A34A15", icon: "✅" },
  { label: "Drop Off At Cleaners", color: "#0EA5E9", bg: "#0EA5E915", icon: "🚗" },
  { label: "At the Cleaners",      color: "#7C5BF5", bg: "#7C5BF515", icon: "👔" },
  { label: "Needs Washing",        color: "#EA580C", bg: "#EA580C15", icon: "🧺" },
  { label: "Dirty",                color: "#DC2626", bg: "#DC262615", icon: "⚠️" },
];

const getStatusMeta = (status) => SUIT_STATUSES.find(s => s.label === status) || SUIT_STATUSES[0];

// Modal for setting drop-off date
const DropOffModal = ({ item, onClose, onSave }) => {
  const [date, setDate] = useState(item.dropOffDate || "");
  return (
    <Modal title="Schedule Drop Off" subtitle={`Set the drop-off date for ${item.name}`} onClose={onClose}>
      <div style={{ marginBottom: 20 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Drop-Off Date</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)}
          style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, background: C.surface, fontSize: 13, color: C.text, boxSizing: "border-box" }} />
        <div style={{ fontSize: 12, color: C.muted, marginTop: 8 }}>This will appear on your dashboard calendar as a reminder.</div>
      </div>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <Btn variant="ghost" onClick={onClose}>Cancel</Btn>
        <Btn onClick={() => { onSave(date); onClose(); }} disabled={!date}>Save Drop-Off Date</Btn>
      </div>
    </Modal>
  );
};

// Modal for setting pickup date
const PickupModal = ({ item, onClose, onSave }) => {
  const [date, setDate] = useState(item.pickupDate || "");
  const [time, setTime] = useState(item.pickupTime || "");
  return (
    <Modal title="Set Pickup Date" subtitle={`When will ${item.name} be ready?`} onClose={onClose}>
      <div style={{ marginBottom: 16 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Pickup Date</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)}
          style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, background: C.surface, fontSize: 13, color: C.text, boxSizing: "border-box" }} />
      </div>
      <div style={{ marginBottom: 20 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Pickup Time (optional)</label>
        <input type="time" value={time} onChange={e => setTime(e.target.value)}
          style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, background: C.surface, fontSize: 13, color: C.text, boxSizing: "border-box" }} />
        <div style={{ fontSize: 12, color: C.muted, marginTop: 8 }}>A reminder will appear on your dashboard calendar.</div>
      </div>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <Btn variant="ghost" onClick={onClose}>Cancel</Btn>
        <Btn onClick={() => { onSave(date, time); onClose(); }} disabled={!date}>Set Pickup Reminder</Btn>
      </div>
    </Modal>
  );
};

const WardrobeModal = ({ suit, onClose, onSave, events, categories }) => {
  const [form, setForm] = useState(suit || {
    name: "", category: "", color: "", notes: "", status: "Clean & Ready", assignedEventId: "",
  });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const upcoming = (events || []).filter(e => e.date >= new Date().toISOString().slice(0,10)).sort((a,b) => a.date > b.date ? 1 : -1);
  const cats = categories || DEFAULT_WARDROBE_CATEGORIES;
  const iStyle = { width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, background: C.surface, fontSize: 13, color: C.text, boxSizing: "border-box", fontFamily: "inherit" };
  return (
    <Modal title={suit ? "Edit Item" : "Add Wardrobe Item"} subtitle={suit ? "Update item details" : "Add a clothing item to your wardrobe"} onClose={onClose}>
      <Input label="Item Name" value={form.name} onChange={v => set("name", v)} placeholder="e.g. Black Tuxedo Jacket, White Dress Shirt" />
      <div style={{ marginBottom: 16 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Category</label>
        <select value={form.category || ""} onChange={e => set("category", e.target.value)} style={iStyle}>
          <option value="">— Select Category —</option>
          {cats.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>
      <Input label="Color / Description" value={form.color} onChange={v => set("color", v)} placeholder="e.g. Midnight Black, Charcoal, Navy Blue" />
      <div style={{ marginBottom: 16 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 8 }}>Status</label>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          {SUIT_STATUSES.map(s => (
            <div key={s.label} onClick={() => set("status", s.label)}
              style={{ padding: "10px 14px", borderRadius: 10, border: `2px solid ${form.status === s.label ? s.color : C.border}`,
                background: form.status === s.label ? s.bg : C.surface, cursor: "pointer",
                display: "flex", alignItems: "center", gap: 8, transition: "all 0.15s" }}>
              <span style={{ fontSize: 16 }}>{s.icon}</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: form.status === s.label ? s.color : C.text }}>{s.label}</span>
            </div>
          ))}
        </div>
      </div>
      <div style={{ marginBottom: 16 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Assign to Event</label>
        <select value={form.assignedEventId || ""} onChange={e => set("assignedEventId", e.target.value)} style={iStyle}>
          <option value="">— Unassigned —</option>
          {upcoming.map(ev => (
            <option key={ev.id} value={ev.id}>{ev.date} — {ev.name || ev.clientName || "Event"}</option>
          ))}
        </select>
      </div>
      <div style={{ marginBottom: 20 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.muted, display: "block", marginBottom: 6 }}>Notes</label>
        <textarea value={form.notes} onChange={e => set("notes", e.target.value)}
          placeholder="e.g. Missing button on left cuff, needs alterations..." rows={3}
          style={{ ...iStyle, resize: "vertical" }} />
      </div>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <Btn variant="ghost" onClick={onClose}>Cancel</Btn>
        <Btn onClick={() => { if (!form.name.trim()) return; onSave(form); }}>Save Item</Btn>
      </div>
    </Modal>
  );
};

const Wardrobe = () => {
  const { wardrobe, setWardrobe, events, wardrobeCategories } = useApp();
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem] = useState(null);
  const [activeStatus, setActiveStatus] = useState("All");
  const [activeCategory, setActiveCategory] = useState("All");
  const [dropOffItem, setDropOffItem] = useState(null);
  const [pickupItem, setPickupItem] = useState(null);
  const [toast, setToast] = useState("");

  const cats = wardrobeCategories || DEFAULT_WARDROBE_CATEGORIES;
  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(""), 2500); };

  const statusTabs = ["All", "Clean & Ready", "Drop Off At Cleaners", "At the Cleaners", "Needs Washing", "Dirty"];

  const updateItem = (id, patch) => setWardrobe(prev => prev.map(s => s.id === id ? { ...s, ...patch } : s));

  // Filter by status then category
  const byStatus = activeStatus === "All" ? wardrobe : wardrobe.filter(s => s.status === activeStatus);
  const displayed = activeCategory === "All" ? byStatus : byStatus.filter(s => s.category === activeCategory);

  const getEventName = (id) => {
    const ev = (events || []).find(e => String(e.id) === String(id));
    if (!ev) return null;
    return `${ev.date} — ${ev.name || ev.client || "Event"}`;
  };

  const handleSave = (form) => {
    if (editItem) {
      updateItem(editItem.id, form);
      showToast("Item updated!");
    } else {
      setWardrobe(prev => [...prev, { ...form, id: Date.now() }]);
      showToast("Item added!");
    }
    setEditItem(null);
    setShowModal(false);
  };

  const readyCount   = wardrobe.filter(s => s.status === "Clean & Ready").length;
  const dropOffCount = wardrobe.filter(s => s.status === "Drop Off At Cleaners").length;
  const cleanerCount = wardrobe.filter(s => s.status === "At the Cleaners").length;
  const dirtyCount   = wardrobe.filter(s => ["Needs Washing","Dirty"].includes(s.status)).length;

  return (
    <div>
      {toast && <Toast msg={toast} onClose={() => setToast("")} />}
      {(showModal || editItem) && (
        <WardrobeModal
          suit={editItem}
          events={events}
          categories={cats}
          onClose={() => { setShowModal(false); setEditItem(null); }}
          onSave={handleSave}
        />
      )}
      {dropOffItem && (
        <DropOffModal
          item={dropOffItem}
          onClose={() => setDropOffItem(null)}
          onSave={(date) => {
            updateItem(dropOffItem.id, { status: "Drop Off At Cleaners", dropOffDate: date });
            showToast(`Drop-off scheduled for ${date}`);
          }}
        />
      )}
      {pickupItem && (
        <PickupModal
          item={pickupItem}
          onClose={() => setPickupItem(null)}
          onSave={(date, time) => {
            updateItem(pickupItem.id, { pickupDate: date, pickupTime: time });
            showToast(`Pickup reminder set for ${date}${time ? " at " + time : ""}`);
          }}
        />
      )}

      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 24 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 900, marginBottom: 4 }}>Wardrobe</h2>
          <p style={{ color: C.muted, fontSize: 13 }}>Track every clothing item — always know what's clean, at the cleaners, or needs attention</p>
        </div>
        <Btn size="sm" onClick={() => { setEditItem(null); setShowModal(true); }}>+ Add Item</Btn>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 16, marginBottom: 20 }}>
        <Stat label="Clean & Ready" value={readyCount.toString()} color={C.green} />
        <Stat label="Drop Off Needed" value={dropOffCount.toString()} color="#0EA5E9" />
        <Stat label="At the Cleaners" value={cleanerCount.toString()} color={C.purple} />
        <Stat label="Needs Attention" value={dirtyCount.toString()} color={C.orange} />
      </div>

      {/* Status tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
        {statusTabs.map(t => {
          const meta = t !== "All" ? getStatusMeta(t) : null;
          const active = activeStatus === t;
          const count = t === "All" ? wardrobe.length : wardrobe.filter(s => s.status === t).length;
          return (
            <div key={t} onClick={() => setActiveStatus(t)}
              style={{ padding: "6px 14px", borderRadius: 20, cursor: "pointer", fontSize: 12, fontWeight: 600,
                background: active ? (meta ? meta.color : C.accent) : C.surface,
                color: active ? "#fff" : C.muted,
                border: `1px solid ${active ? "transparent" : C.border}`,
                display: "flex", alignItems: "center", gap: 6, transition: "all 0.15s" }}>
              {meta && <span>{meta.icon}</span>}
              {t}
              <span style={{ background: active ? "rgba(255,255,255,0.25)" : C.surfaceAlt, borderRadius: 8, padding: "1px 6px", fontSize: 10 }}>{count}</span>
            </div>
          );
        })}
      </div>

      {/* Category filter bar */}
      {wardrobe.length > 0 && (
        <div style={{ display: "flex", gap: 6, marginBottom: 20, flexWrap: "wrap", padding: "10px 14px", background: C.surfaceAlt, borderRadius: 10, border: `1px solid ${C.border}` }}>
          <span style={{ fontSize: 11, fontWeight: 700, color: C.muted, textTransform: "uppercase", letterSpacing: "0.05em", alignSelf: "center", marginRight: 4 }}>Category:</span>
          {["All", ...cats].map(cat => (
            <div key={cat} onClick={() => setActiveCategory(cat)}
              style={{ padding: "4px 12px", borderRadius: 20, cursor: "pointer", fontSize: 12, fontWeight: 600,
                background: activeCategory === cat ? C.accent : C.surface,
                color: activeCategory === cat ? "#fff" : C.muted,
                border: `1px solid ${activeCategory === cat ? "transparent" : C.border}`,
                transition: "all 0.15s" }}>
              {cat}
              {cat !== "All" && (
                <span style={{ marginLeft: 5, fontSize: 10, opacity: 0.7 }}>
                  {wardrobe.filter(s => s.category === cat).length}
                </span>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Empty state */}
      {wardrobe.length === 0 ? (
        <Card style={{ textAlign: "center", padding: 56 }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>👔</div>
          <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>No wardrobe items yet</div>
          <div style={{ color: C.muted, fontSize: 13, marginBottom: 20 }}>Add your suits, shirts, and accessories — track what's clean, dirty, or at the cleaners so you're never caught off guard before a gig</div>
          <Btn onClick={() => setShowModal(true)}>+ Add Your First Item</Btn>
        </Card>
      ) : displayed.length === 0 ? (
        <Card style={{ textAlign: "center", padding: 40 }}>
          <div style={{ fontSize: 32, marginBottom: 10 }}>🔍</div>
          <div style={{ color: C.muted, fontSize: 14 }}>No items match this filter</div>
        </Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 16 }}>
          {displayed.map(item => {
            const meta = getStatusMeta(item.status);
            const eventName = item.assignedEventId ? getEventName(item.assignedEventId) : null;
            return (
              <Card key={item.id} style={{ padding: 20, position: "relative" }}>
                {/* Status bar */}
                <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 4, borderRadius: "12px 12px 0 0", background: meta.color }} />

                {/* Header row */}
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10, marginTop: 4 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 2 }}>{item.name}</div>
                    <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                      {item.category && <span style={{ fontSize: 11, color: C.accent, background: C.accentDim, borderRadius: 6, padding: "2px 8px", fontWeight: 600 }}>{item.category}</span>}
                      {item.color && <span style={{ fontSize: 11, color: C.muted }}>{item.color}</span>}
                    </div>
                  </div>
                  <span style={{ fontSize: 11, fontWeight: 700, color: meta.color, background: meta.bg,
                    padding: "4px 10px", borderRadius: 20, whiteSpace: "nowrap",
                    border: `1px solid ${meta.color}33`, flexShrink: 0, marginLeft: 10 }}>
                    {meta.icon} {meta.label}
                  </span>
                </div>

                {/* Assigned event */}
                {eventName && (
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 10,
                    background: C.accentDim, borderRadius: 8, padding: "7px 10px" }}>
                    <span style={{ fontSize: 13 }}>📅</span>
                    <span style={{ fontSize: 12, color: C.accent, fontWeight: 600 }}>{eventName}</span>
                  </div>
                )}

                {/* Drop-off date */}
                {item.dropOffDate && item.status === "Drop Off At Cleaners" && (
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 10,
                    background: "#0EA5E910", borderRadius: 8, padding: "7px 10px", border: "1px solid #0EA5E930" }}>
                    <span style={{ fontSize: 13 }}>🚗</span>
                    <span style={{ fontSize: 12, color: "#0EA5E9", fontWeight: 600 }}>Drop off: {item.dropOffDate}</span>
                  </div>
                )}

                {/* Pickup date */}
                {item.pickupDate && item.status === "At the Cleaners" && (
                  <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 10,
                    background: C.purple + "10", borderRadius: 8, padding: "7px 10px", border: `1px solid ${C.purple}30` }}>
                    <span style={{ fontSize: 13 }}>📦</span>
                    <span style={{ fontSize: 12, color: C.purple, fontWeight: 600 }}>
                      Pickup: {item.pickupDate}{item.pickupTime ? " at " + item.pickupTime : ""}
                    </span>
                  </div>
                )}

                {/* Notes */}
                {item.notes && (
                  <div style={{ fontSize: 12, color: C.muted, background: C.surfaceAlt,
                    borderRadius: 8, padding: "8px 10px", marginBottom: 10, lineHeight: 1.5 }}>
                    {item.notes}
                  </div>
                )}

                {/* Quick action buttons */}
                <div style={{ display: "flex", gap: 6, flexWrap: "wrap", borderTop: `1px solid ${C.border}`, paddingTop: 12 }}>
                  <Btn size="sm" variant="ghost" onClick={() => { setEditItem(item); setShowModal(true); }}>✏️ Edit</Btn>

                  {/* Clean & Ready → quick status buttons */}
                  {item.status === "Clean & Ready" && (<>
                    <Btn size="sm" variant="ghost" onClick={() => { updateItem(item.id, { status: "Needs Washing" }); showToast("Marked as needs washing"); }}>🧺 Needs Wash</Btn>
                    <Btn size="sm" variant="ghost" onClick={() => { updateItem(item.id, { status: "Dirty" }); showToast("Marked dirty"); }}>⚠️ Dirty</Btn>
                    <Btn size="sm" variant="ghost" onClick={() => setDropOffItem(item)}>🚗 To Cleaners</Btn>
                  </>)}

                  {/* Needs Washing / Dirty → send to cleaners or mark dirty */}
                  {["Needs Washing","Dirty"].includes(item.status) && (<>
                    <Btn size="sm" variant="ghost" onClick={() => setDropOffItem(item)}>🚗 Send to Cleaners</Btn>
                    {item.status === "Needs Washing" && <Btn size="sm" variant="ghost" onClick={() => { updateItem(item.id, { status: "Dirty" }); showToast("Marked dirty"); }}>⚠️ Dirty</Btn>}
                    {item.status === "Dirty" && <Btn size="sm" variant="ghost" onClick={() => { updateItem(item.id, { status: "Needs Washing" }); showToast("Marked needs washing"); }}>🧺 Needs Wash</Btn>}
                  </>)}

                  {/* Drop Off At Cleaners → mark completed drop-off */}
                  {item.status === "Drop Off At Cleaners" && (<>
                    <Btn size="sm" onClick={() => { setPickupItem(item); updateItem(item.id, { status: "At the Cleaners" }); showToast("Dropped off! Set pickup date."); }}>✅ Dropped Off</Btn>
                    {!item.dropOffDate && <Btn size="sm" variant="ghost" onClick={() => setDropOffItem(item)}>📅 Set Date</Btn>}
                  </>)}

                  {/* At the Cleaners → set pickup or mark ready */}
                  {item.status === "At the Cleaners" && (<>
                    {!item.pickupDate && <Btn size="sm" variant="ghost" onClick={() => setPickupItem(item)}>📦 Set Pickup</Btn>}
                    <Btn size="sm" onClick={() => { updateItem(item.id, { status: "Clean & Ready", dropOffDate: null, pickupDate: null, pickupTime: null }); showToast(`${item.name} is clean & ready!`); }}>✅ Picked Up</Btn>
                  </>)}

                  <div style={{ flex: 1 }} />
                  <Btn size="sm" variant="danger" onClick={() => { setWardrobe(prev => prev.filter(s => s.id !== item.id)); showToast("Item removed."); }}>✕</Btn>
                </div>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
};


